export const йҺ®е®…зҶ’жҳҹ = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const з·ҡ = (жӣё, еҜ¬ = 0.38) => bi.дёҖзӯҶ({ еҜ¬: еҜ¬ * u, иө·: 'и—Ҹ', ж”¶: 'еӣһ' }, жӣё);
    const еңҲ = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const йҖЈ = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        з·ҡ(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    // з¬Ұй ӯпјҡж–·жЎҝз¶ҙеңҲдәҢпјӢдәәеӯ—йҸҲпјӢж•ЈеңҲпјӢеҸіеңҲжҹұ
    з·ҡ(p => p.M(X(1.2), Z(1.6)).L(X(1.9), Z(1.57)));
    еңҲ(0.9, 1.6);
    еңҲ(2.2, 1.55);
    з·ҡ(p => p.M(X(3.2), Z(1.5)).L(X(3.7), Z(1.48)));
    еңҲ(2.9, 1.5);
    еңҲ(4.0, 1.45);
    еңҲ(3.3, 2.9);
    йҖЈ([3.3, 2.9], [2.2, 4.0]);
    йҖЈ([3.3, 2.9], [4.3, 4.0]);
    еңҲ(2.2, 4.0);
    еңҲ(4.3, 4.0);
    for (const [x, z] of [[2.3, 5.5], [3.5, 5.6], [2.4, 6.9], [3.6, 7.0]])
        еңҲ(x, z);
    for (const z of [1.0, 2.2, 3.4, 4.6, 5.8, 6.9])
        еңҲ(6.8, z);
    // еҚҢеҚҢеё¶пјҲйӣҷж јжҹөпјү
    const жҹө = (x0, x1) => {
        з·ҡ(p => p.M(X(x0), Z(7.7)).L(X(x1), Z(7.65)));
        з·ҡ(p => p.M(X(x0), Z(9.5)).L(X(x1), Z(9.45)));
        for (let i = 0; i < 4; i++) {
            const x = x0 + 0.4 + i * ((x1 - x0 - 0.8) / 3);
            з·ҡ(p => p.M(X(x), Z(7.4)).L(X(x - 0.02), Z(9.7)), 0.34);
        }
    };
    жҹө(0.9, 3.3);
    жҹө(3.7, 6.2);
    // зҫҪеҚ…её¶
    const зҫҪ = (x0) => {
        з·ҡ(p => p.M(X(x0), Z(10.2)).C(X(x0 - 0.3), Z(11.0), X(x0 - 0.2), Z(11.7), X(x0 + 0.1), Z(12.1)), 0.34);
        з·ҡ(p => p.M(X(x0 + 0.5), Z(10.4)).C(X(x0 + 0.9), Z(10.9), X(x0 + 1.1), Z(11.4), X(x0 + 1.1), Z(11.9)), 0.32);
    };
    зҫҪ(1.2);
    зҫҪ(2.4);
    з·ҡ(p => p.M(X(3.9), Z(10.5)).L(X(6.1), Z(10.45)));
    for (const x of [4.3, 5.0, 5.7])
        з·ҡ(p => p.M(X(x), Z(10.1)).L(X(x - 0.02), Z(11.9)), 0.32);
    // з”°з”°еұӨ
    const з”° = (x0) => {
        з·ҡ(p => p.M(X(x0), Z(12.6)).L(X(x0), Z(15.0)).L(X(x0 + 2.2), Z(14.95))
            .L(X(x0 + 2.2), Z(12.55)).L(X(x0 - 0.05), Z(12.6)));
        з·ҡ(p => p.M(X(x0 + 0.1), Z(13.8)).L(X(x0 + 2.1), Z(13.75)), 0.32);
        з·ҡ(p => p.M(X(x0 + 1.1), Z(12.65)).L(X(x0 + 1.08), Z(14.95)), 0.32);
    };
    з”°(0.9);
    з”°(3.7);
    // еә•зӣ®
    з·ҡ(p => p.M(X(1.0), Z(15.7)).L(X(1.0), Z(19.0)));
    з·ҡ(p => p.M(X(6.0), Z(15.65)).L(X(6.0), Z(18.95)));
    for (const z of [15.7, 17.35, 19.0])
        з·ҡ(p => p.M(X(1.0), Z(z)).L(X(6.0), Z(z - 0.05)));
};
